// Compile-only smoke test for the Tier 1 schema carriers regenerated by
// `tool/regen_tier1.dart`.
//
// Each `<resource>.schema.dart` generated under `lib/src/generated/`
// exposes:
//   - a `$<Resource>` abstract class (terradart-codegen output) annotated
//     with `@TerraformResource` + `@Schema`,
//   - a `<Resource>` base class (schemantic output) implementing the
//     abstract via the `part '*.schema.g.dart';` directive,
//   - a `<resource>Sensitive` top-level `Set<String>` const collected
//     by the emitter (top-level rather than class-member
//     because schemantic's `SchemaGenerator` would otherwise treat it as
//     a required schema property).
//
// This test imports every generated file and reaches into both the
// schemantic `base class` and the terradart-codegen `$Foo` to verify
// the regen pipeline produced reachable Dart symbols. Factory imports
// already point at these generated files; this test
// exists so a regression in regen — missing rename, schemantic build
// failure, dropped resource — fails CI before factories break.
import 'package:terradart_google/src/generated/google_cloud_scheduler_job.schema.dart';
import 'package:terradart_google/src/generated/google_cloud_tasks_queue.schema.dart';
import 'package:terradart_google/src/generated/google_cloud_tasks_queue_iam_member.schema.dart';
import 'package:terradart_google/src/generated/google_project_service.schema.dart';
import 'package:terradart_google/src/generated/google_pubsub_subscription.schema.dart';
import 'package:terradart_google/src/generated/google_pubsub_subscription_iam_member.schema.dart';
import 'package:terradart_google/src/generated/google_pubsub_topic.schema.dart';
import 'package:terradart_google/src/generated/google_pubsub_topic_iam_member.schema.dart';
import 'package:terradart_google/src/generated/google_secret_manager_secret.schema.dart';
import 'package:terradart_google/src/generated/google_secret_manager_secret_iam_member.schema.dart';
import 'package:terradart_google/src/generated/google_secret_manager_secret_version.schema.dart';
import 'package:terradart_google/src/generated/google_service_account.schema.dart';
import 'package:test/test.dart';

void main() {
  test(
    'all 12 generated schemas compile and expose \$Foo + Foo + Sensitive',
    () {
      // The 12 abstract classes terradart-codegen emits — one per Tier 1
      // resource. Reachability of these symbols proves the abstract emitter
      // ran cleanly.
      expect($GooglePubsubTopic, isA<Type>());
      expect($GooglePubsubSubscription, isA<Type>());
      expect($GooglePubsubTopicIamMember, isA<Type>());
      expect($GooglePubsubSubscriptionIamMember, isA<Type>());
      expect($GoogleCloudTasksQueue, isA<Type>());
      expect($GoogleCloudTasksQueueIamMember, isA<Type>());
      expect($GoogleSecretManagerSecret, isA<Type>());
      expect($GoogleSecretManagerSecretVersion, isA<Type>());
      expect($GoogleSecretManagerSecretIamMember, isA<Type>());
      expect($GoogleCloudSchedulerJob, isA<Type>());
      expect($GoogleProjectService, isA<Type>());
      expect($GoogleServiceAccount, isA<Type>());

      // The 12 schemantic-emitted concrete classes (one per `.schema.g.dart`).
      // Reachability proves the build_runner step also ran for every file.
      expect(GooglePubsubTopic, isA<Type>());
      expect(GooglePubsubSubscription, isA<Type>());
      expect(GooglePubsubTopicIamMember, isA<Type>());
      expect(GooglePubsubSubscriptionIamMember, isA<Type>());
      expect(GoogleCloudTasksQueue, isA<Type>());
      expect(GoogleCloudTasksQueueIamMember, isA<Type>());
      expect(GoogleSecretManagerSecret, isA<Type>());
      expect(GoogleSecretManagerSecretVersion, isA<Type>());
      expect(GoogleSecretManagerSecretIamMember, isA<Type>());
      expect(GoogleCloudSchedulerJob, isA<Type>());
      expect(GoogleProjectService, isA<Type>());
      expect(GoogleServiceAccount, isA<Type>());

      // The 12 top-level sensitive-field constants (emitted by
      // `sensitive_set_emitter.dart`). Each is a Set<String>; most
      // resources have an empty set, but google_secret_manager_secret_version
      // is non-empty in the live schema (`secret_data`).
      expect(googlePubsubTopicSensitive, isA<Set<String>>());
      expect(googlePubsubSubscriptionSensitive, isA<Set<String>>());
      expect(googlePubsubTopicIamMemberSensitive, isA<Set<String>>());
      expect(googlePubsubSubscriptionIamMemberSensitive, isA<Set<String>>());
      expect(googleCloudTasksQueueSensitive, isA<Set<String>>());
      expect(googleCloudTasksQueueIamMemberSensitive, isA<Set<String>>());
      expect(googleSecretManagerSecretSensitive, isA<Set<String>>());
      expect(googleSecretManagerSecretVersionSensitive, isA<Set<String>>());
      expect(googleSecretManagerSecretIamMemberSensitive, isA<Set<String>>());
      expect(googleCloudSchedulerJobSensitive, isA<Set<String>>());
      expect(googleProjectServiceSensitive, isA<Set<String>>());
      expect(googleServiceAccountSensitive, isA<Set<String>>());
    },
  );

  test('sensitive consts mirror the provider schema', () {
    // The provider schema marks `secret_data` and `secret_data_wo` as
    // sensitive on `google_secret_manager_secret_version`. The emitter
    // surfaces them as a Set<String> sibling const.
    expect(googleSecretManagerSecretVersionSensitive, contains('secret_data'));
    // Plain non-sensitive resources (topic, subscription, iam bindings,
    // etc.) carry empty sets — machine-derived from the provider
    // schema, no false positives.
    expect(googlePubsubTopicSensitive, isEmpty);
    expect(googleCloudTasksQueueSensitive, isEmpty);
  });
}
